def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        penalty = 0.0
        complexity = 0.0
        extra = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 8):
                penalty += (ratio ** (2 * k)) / (k ** 2 + 1)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j + 3))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 3
            for z in range(1, 5):
                complexity += 1 / (z + ratio)
            score = score * decay + complexity * 1.5
            priorities[i] = score
        elif 3 < ratio <= 4:
            temp_score = 0
            signs = [1 if x % 2 == 0 else -1 for x in range(1, 10)]
            for x in range(1, 10):
                temp_score += signs[x-1] * (ratio ** x) / (x + 1)
            decay = 1.0
            for y in range(1, 6):
                decay *= (1 - 1 / (y + ratio + 4))
            score = abs(temp_score) * decay * 15
            if ratio > 3.5:
                extra = 0
                for n in range(1, 8):
                    extra += (ratio ** n) / (n + 2)
                score += extra * 3
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 13):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 6)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 4)
                else:
                    temp += (ratio ** p) / (p * 5)
            multiplier = 30 if ratio < 2.5 else 20
            score = abs(temp) * multiplier
            if ratio > 2.8:
                ext_penalty = 0
                for m in range(1, 7):
                    ext_penalty += (ratio ** m) / (m + 4)
                score += ext_penalty * 4
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for p in range(1, 17):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 7)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 6)
                elif p % 3 == 0:
                    temp_score += (ratio ** p) / (p * 5)
                else:
                    temp_score -= (ratio ** p) / (p * 4)
            if ratio < 1.25:
                multiplier = 35
            elif ratio < 1.6:
                multiplier = 20
            else:
                multiplier = 12
            score = abs(temp_score) * multiplier
            if 1.85 < ratio < 1.95:
                extra_add = 0
                for q in range(1, 9):
                    extra_add += (ratio ** q) / (q + 5)
                score += extra_add * 3
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 20):
                if p % 6 == 0:
                    temp_score += (ratio ** p) / (p * 4)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 7)
                elif p % 3 == 0:
                    temp_score += (ratio ** p) / (p * 5)
                else:
                    temp_score -= (ratio ** p) / (p * 6)
            if ratio < 0.15:
                multiplier = 40
            elif ratio < 0.3:
                multiplier = 28
            elif ratio < 0.5:
                multiplier = 18
            elif ratio < 0.7:
                multiplier = 10
            else:
                multiplier = 5
            score = abs(temp_score) * multiplier
            if ratio > 0.9:
                extra_penalties = 0
                for n in range(1, 9):
                    extra_penalties += (ratio ** n) / (n + 3)
                score += extra_penalties * 4
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    for i in range(len(priorities)):
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + (z**2) / (bins[i] + 2))
            priorities[i] *= factor
        elif bins[i] <= 0:
            priorities[i] = np.inf
    for i in range(len(priorities)):
        if priorities[i] != np.inf and priorities[i] > 50:
            adjustments = 0
            for r in range(1, 5):
                adjustments += np.log1p(priorities[i]) / (r + priorities[i] % (r+1))
            priorities[i] -= adjustments * 2
            if priorities[i] < 0:
                priorities[i] = 0
    return priorities
